 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import {
 4	  TextInput,
 5	  FormGroup,
 6	  Stack,
 7	  StackItem,
 8	  FormHelperText,
 9	  HelperText,
10	  HelperTextItem,
11	} from '@patternfly/react-core';
12	
13	type LogReplicationInfoFormProps = {
14	  location?: string;
15	  prefix?: string;
16	  onPrefixChange: (val: string) => void;
17	  onLogLocationChange: (val: string) => void;
18	};
19	
20	export const LogReplicationInfoForm: React.FC<LogReplicationInfoFormProps> = ({
21	  location,
22	  prefix,
23	  onPrefixChange,
24	  onLogLocationChange,
25	}) => {
26	  const { t } = useCustomTranslation();
27	  return (
28	    <Stack hasGutter className="odf-mcg__form">
29	      <StackItem>
30	        <FormGroup fieldId="logs-location" label={t('Event log bucket')}>
31	          <TextInput
32	            data-test="logs-location-input"
33	            placeholder={t('Enter a bucket name')}
34	            type="text"
35	            id="logs-location-input"
36	            value={location}
37	            onChange={(_event, val: string) => {
38	              onLogLocationChange(val);
39	            }}
40	            aria-label={t('Prefix')}
41	          />
42	        </FormGroup>
43	      </StackItem>
44	      <StackItem>
45	        <FormGroup fieldId="log-prefix-input-field" label={t('Prefix')}>
46	          <TextInput
47	            data-test="log-prefix-input"
48	            placeholder={t('Enter a prefix')}
49	            type="text"
50	            id="log-prefix-input"
51	            value={prefix}
52	            onChange={(_event, val: string) => {
53	              onPrefixChange(val);
54	            }}
55	            aria-label={t('Log Prefix')}
56	          />
57	          <FormHelperText>
58	            <HelperText>
59	              <HelperTextItem>
60	                {t(
61	                  'Object names starting with given prefix gets synchronised with the target bucket'
62	                )}
63	              </HelperTextItem>
64	            </HelperText>
65	          </FormHelperText>
66	        </FormGroup>
67	      </StackItem>
68	    </Stack>
69	  );
70	};

